import React, { useState, useEffect } from 'react';
import { View, Text, Button } from 'react-native';
import axios from 'axios';

const client_id = 'YOUR_CLIENT_ID';
const client_secret = 'YOUR_CLIENT_SECRET';
const authorizationUrl = 'https://your-auth-server.com/oauth/authorize';
const tokenUrl = 'https://your-auth-server.com/oauth/token';
const redirectUri = 'com.yourapp://callback';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  useEffect(() => {
    if (accessToken) {
      setInterval(refreshTokenIfNeeded, 3600 * 1000); // Refresh token every hour
    }
  }, [accessToken]);

  const authenticate = () => {
    const authLink = `${authorizationUrl}?response_type=code&client_id=${client_id}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=read write`;
    Linking.openURL(authLink);
  };

  const handleRedirect = (event) => {
    const url = event.url;
    if (url.includes(redirectUri)) {
      const code = new URL(url).searchParams.get('code');
      exchangeCodeForTokens(code);
    }
  };

  const exchangeCodeForTokens = async (code) => {
    try {
      const response = await axios.post(tokenUrl, {
        grant_type: 'authorization_code',
        code,
        client_id,
        client_secret,
        redirect_uri: redirectUri
      });

      setAccessToken(response.data.access_token);
      setRefreshToken(response.data.refresh_token);
    } catch (error) {
      console.error('Error exchanging code for tokens:', error);
    }
  };

  const refreshTokenIfNeeded = async () => {
    if (!accessToken || !refreshToken) return;

    try {
      const response = await axios.post(tokenUrl, {
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id,
        client_secret
      });

      setAccessToken(response.data.access_token);
      if (response.data.refresh_token) {
        setRefreshToken(response.data.refresh_token);
      }
    } catch (error) {
      console.error('Error refreshing token:', error);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {accessToken ? (
        <Text>Authenticated with access token</Text>
      ) : (
        <Button title="Authenticate" onPress={authenticate} />
      )}
    </View>
  );
};

export default App;